import { join } from 'node:path';
import { deriveState } from './state.js';
import { parseSummary, loadFile } from './files.js';
import { isDbAvailable, getMilestoneSlices, getSliceTasks } from './gsd-db.js';
import { parseRoadmap, parsePlan } from './parsers-legacy.js';
import { findMilestoneIds } from './milestone-ids.js';
import { resolveMilestoneFile, resolveSliceFile, resolveGsdRootFile, gsdRoot } from './paths.js';
import {
  getLedger,
  getProjectTotals,
  aggregateByPhase,
  aggregateBySlice,
  aggregateByModel,
  aggregateByTier,
  formatTierSavings,
  loadLedgerFromDisk,
  classifyUnitPhase,
} from './metrics.js';
import { loadAllCaptures, countPendingCaptures } from './captures.js';
import { loadEffectiveGSDPreferences } from './preferences.js';
import { runProviderChecks, type ProviderCheckResult } from './doctor-providers.js';
import { generateSkillHealthReport } from './skill-health.js';
import { runEnvironmentChecks, type EnvironmentCheckResult } from './doctor-environment.js';
import { computeProgressScore } from './progress-score.js';
import { getHealthHistory } from './doctor-proactive.js';

import type { Phase } from './types.js';
import type { CaptureEntry } from './captures.js';
import type {
  ProjectTotals,
  PhaseAggregate,
  SliceAggregate,
  ModelAggregate,
  TierAggregate,
  UnitMetrics,
} from './metrics.js';

// ─── Visualizer Types ─────────────────────────────────────────────────────────

export interface VisualizerMilestone {
  id: string;
  title: string;
  status: 'complete' | 'active' | 'pending' | 'parked';
  dependsOn: string[];
  slices: VisualizerSlice[];
}

export interface VisualizerSlice {
  id: string;
  title: string;
  done: boolean;
  active: boolean;
  risk: string;
  depends: string[];
  tasks: VisualizerTask[];
}

export interface VisualizerTask {
  id: string;
  title: string;
  done: boolean;
  active: boolean;
  estimate?: string;
}

export interface CriticalPathInfo {
  milestonePath: string[];
  slicePath: string[];
  milestoneSlack: Map<string, number>;
  sliceSlack: Map<string, number>;
}

export interface AgentActivityInfo {
  currentUnit: { type: string; id: string; startedAt: number } | null;
  elapsed: number;
  completedUnits: number;
  totalSlices: number;
  completionRate: number;
  active: boolean;
  sessionCost: number;
  sessionTokens: number;
}

export interface ChangelogEntry {
  milestoneId: string;
  sliceId: string;
  title: string;
  oneLiner: string;
  filesModified: { path: string; description: string }[];
  completedAt: string;
}

export interface ChangelogInfo {
  entries: ChangelogEntry[];
}

export interface VisualizerSliceRef {
  milestoneId: string;
  sliceId: string;
  title: string;
}

export interface VisualizerSliceActivity extends VisualizerSliceRef {
  completedAt: string;
}

export interface VisualizerStats {
  missingCount: number;
  missingSlices: VisualizerSliceRef[];
  updatedCount: number;
  updatedSlices: VisualizerSliceActivity[];
  recentEntries: ChangelogEntry[];
}

export type DiscussionState = 'undiscussed' | 'draft' | 'discussed';

export interface VisualizerDiscussionState {
  milestoneId: string;
  title: string;
  state: DiscussionState;
  hasContext: boolean;
  hasDraft: boolean;
  lastUpdated: string | null;
}

export interface SliceVerification {
  milestoneId: string;
  sliceId: string;
  verificationResult: string;
  blockerDiscovered: boolean;
  keyDecisions: string[];
  patternsEstablished: string[];
  provides: string[];
  requires: { slice: string; provides: string }[];
}

export interface KnowledgeInfo {
  rules: { id: string; scope: string; content: string }[];
  patterns: { id: string; content: string }[];
  lessons: { id: string; content: string }[];
  exists: boolean;
}

export interface CapturesInfo {
  entries: CaptureEntry[];
  pendingCount: number;
  totalCount: number;
}

export interface ProviderStatusSummary {
  name: string;
  label: string;
  category: string;
  ok: boolean;
  required: boolean;
  message: string;
}

export interface SkillSummaryInfo {
  total: number;
  warningCount: number;
  criticalCount: number;
  topIssue: string | null;
}

/** A single doctor history entry for visualizer display. */
export interface VisualizerDoctorEntry {
  ts: string;
  ok: boolean;
  errors: number;
  warnings: number;
  fixes: number;
  codes: string[];
  issues?: Array<{ severity: string; code: string; message: string; unitId: string }>;
  fixDescriptions?: string[];
  scope?: string;
  summary?: string;
}

/** Current progress score snapshot for health display. */
export interface VisualizerProgressScore {
  level: "green" | "yellow" | "red";
  summary: string;
  signals: Array<{ kind: "positive" | "negative" | "neutral"; label: string }>;
}

export interface HealthInfo {
  budgetCeiling: number | undefined;
  tokenProfile: string;
  truncationRate: number;
  continueHereRate: number;
  tierBreakdown: TierAggregate[];
  tierSavingsLine: string;
  toolCalls: number;
  assistantMessages: number;
  userMessages: number;
  providers: ProviderStatusSummary[];
  skillSummary: SkillSummaryInfo;
  environmentIssues: import("./doctor-environment.js").EnvironmentCheckResult[];
  /** Persisted doctor run history (most recent first, up to 20 entries). */
  doctorHistory?: VisualizerDoctorEntry[];
  /** Current in-memory progress score (null if auto-mode not active). */
  progressScore?: VisualizerProgressScore | null;
}

export interface VisualizerData {
  milestones: VisualizerMilestone[];
  phase: Phase;
  totals: ProjectTotals | null;
  byPhase: PhaseAggregate[];
  bySlice: SliceAggregate[];
  byModel: ModelAggregate[];
  byTier: TierAggregate[];
  tierSavingsLine: string;
  units: UnitMetrics[];
  criticalPath: CriticalPathInfo;
  remainingSliceCount: number;

// Browser-safe TypeScript interfaces for the workflow visualizer.
// Mirrors upstream types from src/resources/extensions/gsd/visualizer-data.ts
// and src/resources/extensions/gsd/metrics.ts — do NOT import from those
// modules directly, as they use Node.js APIs unavailable in the browser.

// ─── Core Structures ──────────────────────────────────────────────────────────

export interface VisualizerTask {
  id: string
  title: string
  done: boolean
  active: boolean
}

export interface VisualizerSlice {
  id: string
  title: string
  done: boolean
  active: boolean
  risk: string
  depends: string[]
  tasks: VisualizerTask[]
}

export interface VisualizerMilestone {
  id: string
  title: string
  status: "complete" | "active" | "pending"
  dependsOn: string[]
  slices: VisualizerSlice[]
}

// ─── Critical Path ────────────────────────────────────────────────────────────

/** Browser-safe variant: slack fields are plain Records, not Maps. */
export interface CriticalPathInfo {
  milestonePath: string[]
  slicePath: string[]
  milestoneSlack: Record<string, number>
  sliceSlack: Record<string, number>
}

// ─── Agent Activity ──────────────────────────────────────────────────────────

export interface AgentActivityInfo {
  currentUnit: { type: string; id: string; startedAt: number } | null
  elapsed: number
  completedUnits: number
  totalSlices: number
  completionRate: number
  active: boolean
  sessionCost: number
  sessionTokens: number
}

// ─── Changelog ────────────────────────────────────────────────────────────────

export interface ChangelogEntry {
  milestoneId: string
  sliceId: string
  title: string
  oneLiner: string
  filesModified: { path: string; description: string }[]
  completedAt: string
}

export interface ChangelogInfo {
  entries: ChangelogEntry[]
}

// ─── Metrics ──────────────────────────────────────────────────────────────────

export interface TokenCounts {
  input: number
  output: number
  cacheRead: number
  cacheWrite: number
  total: number
}

export interface UnitMetrics {
  type: string
  id: string
  model: string
  startedAt: number
  finishedAt: number
  tokens: TokenCounts
  cost: number
  toolCalls: number
  assistantMessages: number
  userMessages: number
  contextWindowTokens?: number
  truncationSections?: number
  continueHereFired?: boolean
  promptCharCount?: number
}

export interface PhaseAggregate {
  phase: string
  units: number
  tokens: TokenCounts
  cost: number
  duration: number
}

export interface SliceAggregate {
  sliceId: string
  units: number
  tokens: TokenCounts
  cost: number
  duration: number
}

export interface ModelAggregate {
  model: string
  units: number
  tokens: TokenCounts
  cost: number
  contextWindowTokens?: number
}

